commonMistakes.correctCode:
-- Always EXPLAIN new queries against production-like data
EXPLAIN SELECT * FROM orders WHERE status = 'paid' AND amount > 5000;
-- If type=ALL, add an index before deploying.
CREATE INDEX idx_orders_status_amount ON orders(status, amount);

codingChallenges.solution:
CREATE TABLE users (id INT PRIMARY KEY, name VARCHAR(50), email VARCHAR(100));
INSERT INTO users VALUES (1,'Aarav Sharma','aarav@example.com'),
                        (2,'Priya Nair','priya@example.com');

-- Before index
EXPLAIN SELECT * FROM users WHERE email = 'aarav@example.com';
-- type=ALL, rows=2

CREATE INDEX idx_users_email ON users(email);

-- After index
EXPLAIN SELECT * FROM users WHERE email = 'aarav@example.com';
-- type=ref, key=idx_users_email, rows=1
-- Explanation: B-Tree lookup replaces full scan; on a big table this is 1000x+ faster.

CREATE TABLE orders (
  id INT PRIMARY KEY,
  customer_id INT,
  order_date DATE,
  amount DECIMAL(10,2),
  status VARCHAR(20)
);

CREATE INDEX idx_orders_cust_date
  ON orders(customer_id, order_date);

-- Test:
EXPLAIN SELECT * FROM orders
 WHERE customer_id = 101 AND order_date >= '2026-01-01';
-- type=range, key=idx_orders_cust_date
